1	"use client"
2	
3	import * as React from "react"
4	
5	import { cn } from "@/lib/utils"
6	
7	type StepperContextProps = {
8	  activeStep: number
9	  orientation: "horizontal" | "vertical"
10	}
11	
12	const StepperContext = React.createContext<StepperContextProps | null>(null)
13	
14	function useStepper() {
15	  const context = React.useContext(StepperContext)
16	
17	  if (!context) {
18	    throw new Error("useStepper must be used within a <Stepper />")
19	  }
20	
21	  return context
22	}
23	
24	type StepperItemContextProps = {
25	  step: number
26	  state: "completed" | "active" | "pending"
27	}
28	
29	const StepperItemContext = React.createContext<StepperItemContextProps | null>(
30	  null
31	)
32	
33	function useStepperItem() {
34	  const context = React.useContext(StepperItemContext)
35	
36	  if (!context) {
37	    throw new Error("useStepperItem must be used within a <StepperItem />")
38	  }
39	
40	  return context
41	}
42	
43	function Stepper({
44	  activeStep,
45	  orientation = "horizontal",
46	  className,
47	  children,
48	  ...props
49	}: React.ComponentProps<"div"> & {
50	  activeStep: number
51	  orientation?: "horizontal" | "vertical"
52	}) {
53	  return (
54	    <StepperContext.Provider value={{ activeStep, orientation }}>
55	      <div
56	        data-slot="stepper"
57	        data-orientation={orientation}
58	        className={cn("group/stepper", className)}
59	        {...props}
60	      >
61	        {children}
62	      </div>
63	    </StepperContext.Provider>
64	  )
65	}
66	
67	function StepperItem({
68	  step,
69	  className,
70	  children,
71	  ...props
72	}: React.ComponentProps<"div"> & { step: number }) {
73	  const { activeStep, orientation } = useStepper()
74	  const state =
75	    step < activeStep ? "completed" : step === activeStep ? "active" : "pending"
76	
77	  return (
78	    <StepperItemContext.Provider value={{ step, state }}>
79	      <div
80	        data-slot="stepper-item"
81	        data-step={step}
82	        data-state={state}
83	        data-orientation={orientation}
84	        className={cn(
85	          "group/stepper-item relative flex flex-1 items-center gap-2 last:flex-initial",
86	          className
87	        )}
88	        {...props}
89	      >
90	        {children}
91	      </div>
92	    </StepperItemContext.Provider>
93	  )
94	}
95	
96	function StepperTrigger({
97	  className,
98	  children,
99	  ...props
100	}: React.ComponentProps<"button">) {
101	  const { step, state } = useStepperItem()
102	
103	  return (
104	    <button
105	      data-slot="stepper-trigger"
106	      data-state={state}
107	      className={cn(
108	        "inline-flex size-8 shrink-0 items-center justify-center rounded-full border text-sm font-medium transition-colors focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 focus-visible:outline-1 focus-visible:outline-ring disabled:pointer-events-none disabled:opacity-50 data-[state=active]:border-primary data-[state=active]:bg-primary data-[state=active]:text-primary-foreground data-[state=completed]:border-primary data-[state=completed]:bg-primary data-[state=completed]:text-primary-foreground data-[state=pending]:border-muted-foreground/40 data-[state=pending]:text-muted-foreground",
109	        className
110	      )}
111	      {...props}
112	    >
113	      {children ?? step}
114	    </button>
115	  )
116	}
117	
118	function StepperTitle({
119	  className,
120	  ...props
121	}: React.ComponentProps<"p">) {
122	  return (
123	    <p
124	      data-slot="stepper-title"
125	      className={cn("text-sm font-medium whitespace-nowrap", className)}
126	      {...props}
127	    />
128	  )
129	}
130	
131	function StepperDescription({
132	  className,
133	  ...props
134	}: React.ComponentProps<"p">) {
135	  return (
136	    <p
137	      data-slot="stepper-description"
138	      className={cn("text-sm text-muted-foreground", className)}
139	      {...props}
140	    />
141	  )
142	}
143	
144	function StepperSeparator({
145	  className,
146	  ...props
147	}: React.ComponentProps<"div">) {
148	  const { orientation } = useStepper()
149	  const { state } = useStepperItem()
150	
151	  return (
152	    <div
153	      data-slot="stepper-separator"
154	      data-orientation={orientation}
155	      data-state={state === "completed" ? "completed" : "pending"}
156	      className={cn(
157	        "bg-muted transition-colors data-[state=completed]:bg-primary data-[orientation=horizontal]:h-0.5 data-[orientation=horizontal]:w-full data-[orientation=horizontal]:flex-1 data-[orientation=vertical]:h-full data-[orientation=vertical]:min-h-4 data-[orientation=vertical]:w-0.5",
158	        className
159	      )}
160	      {...props}
161	    />
162	  )
163	}
164	
165	function StepperContent({
166	  step,
167	  className,
